<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Facades\Validator;

class LinkPreviewController extends Controller
{
    public function show(Request $request)
    {
        $validator = Validator::make($request->all(), [
            'url' => ['required', 'string'],
        ]);

        if ($validator->fails()) {
            return response()->json([
                'message' => 'Invalid URL provided.',
                'errors' => $validator->errors(),
            ], 422);
        }

        $url = trim($request->input('url'));

        if (!filter_var($url, FILTER_VALIDATE_URL)) {
            return response()->json([
                'message' => 'The provided URL is not valid.',
            ], 422);
        }

        $cacheKey = 'link_preview:' . sha1($url);

        $preview = Cache::remember($cacheKey, now()->addMinutes(30), function () use ($url) {
            return $this->fetchPreview($url);
        });

        if (!$preview) {
            return response()->json([
                'message' => 'Unable to fetch preview for the provided URL.',
            ], 422);
        }

        return response()->json($preview);
    }

    protected function fetchPreview(string $url): ?array
    {
        $ch = curl_init();

        curl_setopt_array($ch, [
            CURLOPT_URL => $url,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_FOLLOWLOCATION => true,
            CURLOPT_MAXREDIRS => 5,
            CURLOPT_CONNECTTIMEOUT => 10,
            CURLOPT_TIMEOUT => 20,
            CURLOPT_USERAGENT => 'Mozilla/5.0 (compatible; LinkPreviewBot/1.0)',
            CURLOPT_SSL_VERIFYPEER => true,
            CURLOPT_SSL_VERIFYHOST => 2,
            CURLOPT_HEADER => true,
        ]);

        $response = curl_exec($ch);

        if ($response === false) {
            curl_close($ch);
            return null;
        }

        $headerSize = curl_getinfo($ch, CURLINFO_HEADER_SIZE);
        $contentType = curl_getinfo($ch, CURLINFO_CONTENT_TYPE);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($httpCode < 200 || $httpCode >= 400) {
            return null;
        }

        $body = substr($response, $headerSize);

        $title = null;
        $description = null;
        $image = null;
        $siteName = null;

        libxml_use_internal_errors(true);

        $dom = new \DOMDocument();
        @$dom->loadHTML($body);
        $xpath = new \DOMXPath($dom);

        $titleNode = $xpath->query('//title')->item(0);
        if ($titleNode) {
            $title = trim($titleNode->textContent);
        }

        $metaTags = [
            'description' => [
                '//meta[@name="description"]/@content',
                '//meta[@property="og:description"]/@content',
            ],
            'image' => [
                '//meta[@property="og:image"]/@content',
                '//meta[@name="twitter:image"]/@content',
            ],
            'site_name' => [
                '//meta[@property="og:site_name"]/@content',
            ],
        ];

        foreach ($metaTags['description'] as $query) {
            $node = $xpath->query($query)->item(0);
            if ($node) {
                $description = trim($node->nodeValue);
                break;
            }
        }

        foreach ($metaTags['image'] as $query) {
            $node = $xpath->query($query)->item(0);
            if ($node) {
                $image = trim($node->nodeValue);
                break;
            }
        }

        foreach ($metaTags['site_name'] as $query) {
            $node = $xpath->query($query)->item(0);
            if ($node) {
                $siteName = trim($node->nodeValue);
                break;
            }
        }

        if (!$title && !$description && !$image) {
            return null;
        }

        return [
            'url' => $url,
            'title' => $title,
            'description' => $description,
            'image' => $image,
            'site_name' => $siteName,
            'content_type' => $contentType,
        ];
    }
}